INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.17.75','cb','cb.adi.17','ЧБ Ади 17.75',75,'শিবগয়া-ব্রহ্মগয়া-আদি যত আছে ।
সব করি’ ষোড়শগয়ায় গেলা পাছে ॥৭৫॥','ш́ива-гайа̄ брахма-гайа̄ а̄ди йата а̄чхе
саба кари’ ш̣од̣аш́а-гайа̄йа гела̄ па̄чхе',NULL,NULL),('cb.adi.17.76','cb','cb.adi.17','ЧБ Ади 17.76',76,'ষোড়শগয়ায় প্রভু ষোড়শী করিয়া ।
সবারে দিলেন পি শ্রদ্ধা-যুক্ত হৈয়া ॥৭৬॥','ш̣од̣аш́а-гайа̄йа прабху ш̣од̣аш́ӣ карийа̄
саба̄ре дилена пин̣д̣а ш́раддха̄-йукта хаийа̄',NULL,NULL),('cb.adi.17.77','cb','cb.adi.17','ЧБ Ади 17.77',77,'তবে মহাপ্রভু ব্রহ্মকুণ্ডে করি’ স্নান ।
গয়া-শিরে আসি’ করিলেন পি দান ॥৭৭॥','тобе маха̄прабху брахма-кун̣д̣е кари’ сна̄на
гайа̄-ш́ире а̄си’ карилена пин̣д̣а да̄на',NULL,NULL),('cb.adi.17.78','cb','cb.adi.17','ЧБ Ади 17.78',78,'দিব্য মালা-চন্দন শ্রীহস্তে প্রভু লৈয়া ।
বিষ্ণুপদচিহ্ন পূজিলেন হর্ষ হৈয়া ॥৭৮॥','дивйа ма̄ла̄-чандана ш́рӣ-хасте прабху лаийа̄
виш̣н̣у-пада-чихна пӯджилена харш̣а хаийа̄',NULL,NULL),('cb.adi.17.79','cb','cb.adi.17','ЧБ Ади 17.79',79,'এইমত সর্ব্বস্থানে শ্রাদ্ধাদি করিয়া ।
বাসায় চলিলা বিপ্রগণে সন্তোষিয়া ॥৭৯॥','эи-мата сарва-стха̄не ш́ра̄ддха̄ди карийа̄
ва̄са̄йа чалила̄ випра-ган̣е сантош̣ийа̄',NULL,NULL),('cb.adi.17.79-2','cb','cb.adi.17','ЧБ Ади 17.79',79,'এইমত সর্ব্বস্থানে শ্রাদ্ধাদি করিয়া ।
বাসায় চলিলা বিপ্রগণে সন্তোষিয়া ॥৭৯॥','эи-мата сарва-стха̄не ш́ра̄ддха̄ди карийа̄
ва̄са̄йа чалила̄ випра-ган̣е сантош̣ийа̄',NULL,NULL),('cb.adi.17.80','cb','cb.adi.17','ЧБ Ади 17.80',80,'তবে মহাপ্রভু কতক্ষণে সুস্থ হৈয়া ।
রন্ধন করিতে প্রভু বসিলেন গিয়া ॥৮০॥','табе маха̄прабху ката-кш̣ан̣е сустха хаийа̄
рандхана карите прабху василена гийа̄',NULL,NULL),('cb.adi.17.81','cb','cb.adi.17','ЧБ Ади 17.81',81,'রন্ধন সম্পূর্ণ হৈল, হেনই সময় ।
আইলেন শ্রীঈশ্বরপুরী মহাশয় ॥৮১॥','рандхана сампӯрн̣а хаила, хенаи самайа
а̄илена ш́рӣ-ӣш́вара-пурӣ маха̄ш́айа',NULL,NULL),('cb.adi.17.82','cb','cb.adi.17','ЧБ Ади 17.82',82,'প্রেমযোগে কৃষ্ণনাম বলিতে বলিতে ।
আইলেন প্রভু-স্থানে ঢুলিতে ঢুলিতে ॥৮২॥','према-йоге кр̣ш̣н̣а-на̄ма балите балите
а̄илена прабху-стха̄не д̣хулите д̣хулите',NULL,NULL),('cb.adi.17.83','cb','cb.adi.17','ЧБ Ади 17.83',83,'রন্ধন এড়িয়া প্রভু পরম-সম্ভ্রমে ।
নমস্করি’ তানে বসাইলেন আসনে ॥৮৩॥','рандхана эд̣ийа̄ прабху парама-самбхраме
намаскари’ та̄не васа̄илена а̄сане',NULL,NULL),('cb.adi.17.84','cb','cb.adi.17','ЧБ Ади 17.84',84,'হাসিয়া বলেন পুরী,—“শুনহ, পণ্ডিত ! ।
ভালই সময়ে হইলাঙ উপনীত” ॥৮৪॥','ха̄сийа̄ балена пурӣ,–‘ш́унаха, пан̣д̣ита!
бха̄лаи самайе хаила̄н̇а упанӣта’',NULL,NULL),('cb.adi.17.85','cb','cb.adi.17','ЧБ Ади 17.85',85,'প্রভু বলে,—“যবে হৈল ভাগ্যের উদয় ।
এই অন্ন ভিক্ষা আজি কর’ মহাশয়” ॥৮৫॥','прабху бале,–‘йабе хаила бха̄гйера удайа
эи анна бхикш̣а̄ а̄джи кара маха̄ш́айа’',NULL,NULL),('cb.adi.17.86','cb','cb.adi.17','ЧБ Ади 17.86',86,'হাসিয়া বলেন পুরী,—“তুমি কি পাইবে?” ।
প্রভু বলে,—“আমি অন্ন রান্ধিবাঙ এবে” ॥৮৬॥','ха̄сийа̄ балена пурӣ,–‘туми ки па̄ибе?’
прабху бале,–‘а̄ми анна ра̄ндхиба̄н̇а эбе’',NULL,NULL),('cb.adi.17.87','cb','cb.adi.17','ЧБ Ади 17.87',87,'পুরী বলে,—“কি-কার্য্যে করিবে আর পাক? ।
যে অন্ন আছয়ে, তাহা কর’ দুইভাগ” ॥৮৭॥','пурӣ бале, — ‘ки-ка̄рйе карибе а̄ра па̄ка?
йе анна а̄чхайе, та̄ха̄ кара’ дуи-бха̄га',NULL,NULL),('cb.adi.17.88','cb','cb.adi.17','ЧБ Ади 17.88',88,'হাসিয়া বলেন প্রভু,—“যদি আমা’ চাও ।
যে অন্ন হৈয়াছে, তাহা তুমি সব খাও ॥৮৮॥','ха̄сийа̄ балена прабху, — ‘йади а̄ма̄’ ча̄о
йе анна хаийа̄чхе, та̄ха̄ туми саба кха̄о',NULL,NULL),('cb.adi.17.89','cb','cb.adi.17','ЧБ Ади 17.89',89,'তিলার্দ্ধেকে আর অন্ন রান্ধিবাঙ আমি ।
না কর’ সঙ্কোচ কিছু, ভিক্ষা কর’ তুমি” ॥৮৯॥','тила̄рддхеке а̄ра анна ра̄ндхиба̄н̇а а̄ми
на̄ кара’ сан̇коча кичху, бхикш̣а̄ кара, туми’',NULL,NULL),('cb.adi.17.90','cb','cb.adi.17','ЧБ Ади 17.90',90,'তবে প্রভু আপনার অন্ন তাঁরে দিয়া ।
আর অন্ন রান্ধিতে সে গেলা হর্ষ হৈয়া ॥৯০॥','табе прабху а̄пана̄ра анна та̄н̇ре дийа̄
а̄ра анна ра̄ндхите се гела̄ харш̣а хаийа̄',NULL,NULL),('cb.adi.17.91','cb','cb.adi.17','ЧБ Ади 17.91',91,'হেন কৃপা প্রভুর ঈশ্বরপুরী-প্রতি ।
পুরীরো নাহিক কৃষ্ণ-ছাড়া অন্য-মতি ॥৯১॥','хена кр̣па̄ прабхура ӣш́вара-пурӣ-прати
пурӣр о на̄хика кр̣ш̣н̣а-чха̄д̣а̄ анйа-мати',NULL,NULL),('cb.adi.17.92','cb','cb.adi.17','ЧБ Ади 17.92',92,'শ্রীহস্তে আপনে প্রভু করে পরিবেশন ।
পরানন্দ-সুখে পুরী করেন ভোজন ॥৯২॥','ш́рӣ-хасте а̄пане прабху каре паривеш́ана
пара̄нанда-сукхе пурӣ карена бходжана',NULL,NULL),('cb.adi.17.93','cb','cb.adi.17','ЧБ Ади 17.93',93,'সেইক্ষণে রমা-দেবী অতি-অলক্ষিতে ।
প্রভুর নিমিত্ত অন্ন রান্ধিলা ত্বরিতে ॥৯৩॥','сеи-кш̣ан̣е рама̄-девӣ ати-алакш̣ите
прабхура нимитта анна рандхила̄ тварите',NULL,NULL),('cb.adi.17.94','cb','cb.adi.17','ЧБ Ади 17.94',94,'তবে প্রভু আগে তানে ভিক্ষা করাইয়া ।
আপনেও ভোজন করিলা হর্ষ হৈয়া ॥৯৪॥','табе прабху а̄ге та̄не бхикш̣а кара̄ийа̄
а̄пане о бходжана карила̄ харш̣а хаийа̄',NULL,NULL),('cb.adi.17.95','cb','cb.adi.17','ЧБ Ади 17.95',95,'ঈশ্বরপুরীর সঙ্গে প্রভুর ভোজন ।
ইহার শ্রবণে মিলে কৃষ্ণপ্রেমধন ॥৯৫॥','ӣш́вара-пурӣра сан̇ге прабхура бходжана
иха̄ра ш́раван̣е миле кр̣ш̣н̣а-према-дхана',NULL,NULL),('cb.adi.17.96','cb','cb.adi.17','ЧБ Ади 17.96',96,'তবে প্রভু ঈশ্বরপুরীর সর্ব্ব-অঙ্গে ।
আপনে-শ্রীহস্তে লেপিলেন দিব্যগন্ধে ॥৯৬॥','табе прабху ӣш́вара-пурера сарва-ан̇ге
а̄пане ш́рӣ-хасте лепилена дивйа-гандхе',NULL,NULL),('cb.adi.17.97','cb','cb.adi.17','ЧБ Ади 17.97',97,'যত প্রীত ঈশ্বরের ঈশ্বরপুরীরে ।
তাহা বর্ণিবারে কোন্ জন শক্তি ধরে? ॥৯৭॥','йата прӣта ӣш́варера ӣш́вара-пурере
та̄ха̄ варн̣иба̄ре кон джана ш́акти дхаре',NULL,NULL),('cb.adi.17.98','cb','cb.adi.17','ЧБ Ади 17.98',98,'আপনে ঈশ্বর শ্রীচৈতন্য ভগবান্ ।
দেখিলেন ঈশ্বরপুরীর জন্মস্থান ॥৯৮॥','а̄пане ӣш́вара ш́рӣ-чаитанйа бхагава̄н
декхилена ӣш́вара-пурӣра джанма-стха̄на',NULL,NULL),('cb.adi.17.99','cb','cb.adi.17','ЧБ Ади 17.99',99,'প্রভু বলে,—“কুমারহট্টেরে নমস্কার ।
শ্রীঈশ্বরপুরীর যে-গ্রামে অবতার” ॥৯৯॥','прабху бале,–‘кума̄рахат̣т̣ерер намаска̄ра
ш́рӣ-ӣш́вара-пурӣра йе-гра̄ме авата̄ра’',NULL,NULL),('cb.adi.17.100','cb','cb.adi.17','ЧБ Ади 17.100',100,'কান্দিলেন বিস্তর চৈতন্য সেই স্থানে ।
আর শব্দ কিছু নাহি ‘ঈশ্বরপুরী’ বিনে ॥১০০॥','ка̄ндилена вистара чаитанйа сеи стха̄не
а̄ра ш́абда кичху на̄хи ‘ӣш́вара-пурӣ’ вине',NULL,NULL),('cb.adi.17.101','cb','cb.adi.17','ЧБ Ади 17.101',101,'সে-স্থানের মৃত্তিকা আপনে প্রভু তুলি’ ।
লইলেন বহির্ব্বাসে বান্ধি’ এক ঝুলি ॥১০১॥','се-стха̄нера мр̣ттика̄ а̄пане прабху тули’
лаилена бахирва̄се ба̄ндхи’ эка джхӯли',NULL,NULL),('cb.adi.17.102','cb','cb.adi.17','ЧБ Ади 17.102',102,'প্রভু বলে,—“ঈশ্বরপুরীর জন্মস্থান ।
এ মৃত্তিকা—আমার জীবন ধন-প্রাণ” ॥১০২॥','прабху бале,–‘ӣш́вара-пурӣра джанма-стха̄на
э мр̣ттика̄-а̄ма̄ра джӣвана дхана-пра̄н̣а',NULL,NULL),('cb.adi.17.103','cb','cb.adi.17','ЧБ Ади 17.103',103,'হেন ঈশ্বরের প্রীত ঈশ্বরপুরীরে ।
ভক্তেরে বাড়াতে প্রভু সব শক্তি ধরে ॥১০৩॥','хена ӣш́варера прӣта ӣш́вара-пурӣре
бхактере ба̄д̣а̄те прабху саба ш́акти дхаре',NULL,NULL),('cb.adi.17.104','cb','cb.adi.17','ЧБ Ади 17.104',104,'প্রভু বলে,—“গয়া করিতে যে আইলাঙ ।
সত্য হৈল,—ঈশ্বরপুরীরে দেখিলাঙ” ॥১০৪॥','прабху бале, – ‘гайа̄ карите йе а̄ила̄н̇а
сатйа хаила, — ӣш́вара-пурӣре дехкила̄н̇а’',NULL,NULL),('cb.adi.17.105','cb','cb.adi.17','ЧБ Ади 17.105',105,'আর দিনে নিভৃতে ঈশ্বরপুরী-স্থানে ।
মন্ত্র-দীক্ষা চাহিলেন মধুর-বচনে ॥১০৫॥','а̄ра дине нибхр̣те ӣш́вара-пурӣ-стха̄не
мантра-дӣкш̣а̄ ча̄хилена мадхура-вачане',NULL,NULL),('cb.adi.17.106','cb','cb.adi.17','ЧБ Ади 17.106',106,'পুরী বলে,—“মন্ত্র বা বলিয়া কোন্ কথা? ।
প্রাণ আমি দিতে পারি তোমারে সর্ব্বথা” ॥১০৬॥','пурӣ бале, — ‘мантра ва̄ балийа̄ кон катха̄?
пра̄н̣а а̄ми дите па̄ри тома̄ре сарватха̄’',NULL,NULL),('cb.adi.17.107','cb','cb.adi.17','ЧБ Ади 17.107',107,'তবে তান স্থানে শিক্ষা-গুরু নারায়ণ ।
করিলেন দশাক্ষর-মন্ত্রের গ্রহণ ॥১০৭॥','табе та̄на стха̄не ш́икш̣а̄-гуру на̄ра̄йан̣а
карилена даш́а̄кш̣ара-мантрера грахан̣а',NULL,NULL),('cb.adi.17.108','cb','cb.adi.17','ЧБ Ади 17.108',108,'তবে প্রভু প্রদক্ষিণ করিয়া পুরীরে ।
প্রভু বলে,—“দেহ আমি দিলাঙ তোমারে ॥১০৮॥','табе прабху прадакш̣ин̣а карийа̄ пурӣре
прабху бале, — ‘деха а̄ми дила̄н̇а тома̄ре',NULL,NULL),('cb.adi.17.109','cb','cb.adi.17','ЧБ Ади 17.109',109,'হেন শুভদৃষ্টি তুমি করহ আমারে ।
যেন আমি ভাসি কৃষ্ণপ্রেমের সাগরে” ॥১০৯॥','хена ш́убха-др̣ш̣т̣и туми караха а̄ма̄ре
йена а̄ми бха̄си кр̣ш̣н̣а-премера са̄гаре’',NULL,NULL),('cb.adi.17.110','cb','cb.adi.17','ЧБ Ади 17.110',110,'শুনিয়া প্রভুর বাক্য শ্রীঈশ্বরপুরী ।
প্রভুরে দিলেন আলিঙ্গন বক্ষে ধরি’॥১১০॥','ш́унийа̄ прабхура ва̄кйа ш́рӣ-ӣш́вара-пурӣ
‘прабхуре дилена а̄лин̇гана вакш̣е дхари’',NULL,NULL),('cb.adi.17.111','cb','cb.adi.17','ЧБ Ади 17.111',111,'দোঁহার নয়নজলে দোঁহার শরীর ।
সিঞ্চিত হইলা প্রেমে, কেহ নহে স্থির ॥১১১॥3','дон̇ха̄ра найана-джале дон̇ха̄ра ш́арӣра
син̃чита хаила̄ преме, кеха нахе стхира',NULL,NULL),('cb.adi.17.112','cb','cb.adi.17','ЧБ Ади 17.112',112,'হেনমতে ঈশ্বরপুরীরে কৃপা করি’ ।
